   369→int q6apm_graph_media_format_pcm(struct q6apm_graph *graph, struct audioreach_module_config *cfg)
   370→{
   371→	struct audioreach_graph_info *info = graph->info;
   372→	struct audioreach_sub_graph *sgs;
